@startuml
!theme plain
title AI's Class Diagram

package "com" {
  package "dekinci" {
    package "eden" {
      package "model" {
        package "animal" {
          package "ai" {
            class "AnimalVision" {
              - grass : double[]
              - hares : double[]
              - wolves : double[]
              - land : double[]
              - water : double[]
              + AnimalVision()
              + getjoined()
            }
            class "DoubleToGrayCode" {
              - minValue : int
              - maxValue : int
              - size : int
              - bits : int
              - pieces : int
              + doubleToGC()
              + gCToDouble()
            }
            class "Brain" {
              + Brain()
              + Brain()
              + breed()
              + makeDecision()
            }
            class "VisionFactory" {
              - animalSight : int
              + VisionFactory()
              + seeBlocks()
              + seeGrass()
              + seeAnimals()
              + getPoint()
            }
            class "Genotype" {
              - genes : int[]
              + Genotype()
              + getGenes()
              + breed()
              - crossover()
              - arrayExchange()
              - bitExchange()
              - mutation()
            }
            class "NeuralNetwork" {
              - inputLayer : double[][]
              - innerLayers : double[][][]
              - outputLayer : double[][]
              - inputSize : int
              - innerSize : int
              - outputSize : int
              + NeuralNetwork()
              + NeuralNetwork()
              + genotype()
              + calculate()
              - activationF()
            }
            "Brain" ..> "NeuralNetwork" : neuralNetwork
          }
        }
      }
    }
  }
}

class "Coordinate" {
  + Coordinate()
}
class "WorldMap" {
  + WorldMap()
}
class "AnimalManager" {
  + AnimalManager()
}

"VisionFactory" --> "Coordinate" : worldMap
"VisionFactory" --> "WorldMap" : manager
"VisionFactory" --> "AnimalManager" : manager

@enduml
